    /**
     * Solves the problem of finding the minimum number of elements to remove from nums
     * such that the XOR sum of the remaining elements equals target.
     *
     * @param nums The integer array.
     * @param target The target XOR sum.
     * @return The minimum number of removals, or -1 if impossible.
     */
    public static long solve(long[] nums, long target) {
        int n = nums.length;
        if (n == 0) {
            return target == 0 ? 0 : -1;
        }

        // Since N is small (up to 40), we can use Meet-in-the-Middle (MITM).
        // 2^40 is too large, but 2^20 is manageable.

        int n1 = n / 2;
        int n2 = n - n1;

        // Step 1: Generate all possible XOR sums for the first half (nums[0...n1-1])
        // Store: XOR_sum -> minimum number of elements used to achieve this sum
        // We use a map or, since we only care about the *number* of removed elements,
        // let's store: XOR_sum -> minimum number of elements *kept*
        // The number of removals = original_size - kept_size

        // For the first half (size n1), we generate all 2^n1 subsets.
        // Map: XOR_sum -> minimum size of subset achieving this sum
        java.util.Map<Long, Integer> map1 = new java.util.HashMap<>();

        // Iterate through all 2^n1 subsets using bitmasks
        for (int i = 0; i < (1 << n1); i++) {
            long currentXor = 0;
            int count = 0;
            for (int j = 0; j < n1; j++) {
                if ((i & (1 << j)) != 0) {
                    currentXor ^= nums[j];
                    count++;
                }
            }

            // Store the minimum count for this XOR sum
            map1.put(currentXor, Math.min(map1.getOrDefault(currentXor, n1 + 1), count));
        }

        // Step 2: Generate all possible XOR sums for the second half (nums[n1...n-1])
        // Map: XOR_sum -> minimum size of subset achieving this sum
        java.util.Map<Long, Integer> map2 = new java.util.HashMap<>();

        // Iterate through all 2^n2 subsets using bitmasks
        for (int i = 0; i < (1 << n2); i++) {
            long currentXor = 0;
            int count = 0;
            for (int j = 0; j < n2; j++) {
                if ((i & (1 << j)) != 0) {
                    currentXor ^= nums[n1 + j];
                    count++;
                }
            }

            // Store the minimum count for this XOR sum
            map2.put(currentXor, Math.min(map2.getOrDefault(currentXor, n2 + 1), count));
        }

        // Step 3: Combine results
        // We want (Xor1 ^ Xor2) = target, which means Xor2 = target ^ Xor1.
        // We want to maximize (kept_count1 + kept_count2) to minimize removals.
        int maxKeptCount = -1;

        for (java.util.Map.Entry<Long, Integer> entry1 : map1.entrySet()) {
            long xor1 = entry1.getKey();
            int count1 = entry1.getValue();

            long requiredXor2 = target ^ xor1;

            if (map2.containsKey(requiredXor2)) {
                int count2 = map2.get(requiredXor2);
                int totalKeptCount = count1 + count2;
                maxKeptCount = Math.max(maxKeptCount, totalKeptCount);
            }
        }

        // Special case: Empty set combination (Xor = 0, Count = 0)
        // This is implicitly covered by map1/map2 containing {0: 0} if we consider the empty subset.
        // Let's ensure {0: 0} is present for both halves if it wasn't naturally included (it should be).
        map1.putIfAbsent(0L, 0);
        map2.putIfAbsent(0L, 0);

        // Re-check combination including the explicit {0: 0} case if needed, but the loop should handle it.
        // If target=0, we check if map1.get(0) + map2.get(0) >= 0.

        if (maxKeptCount == -1) {
            return -1;
        }

        // Minimum removals = Total elements - Maximum kept elements
        return (long) n - maxKeptCount;
    }
