    /**
     * Generates all possible XOR sums from all subsets of nums.
     * Since N is small (<= 40), we can use meet-in-the-middle or DP/recursion.
     * Given the constraints (N <= 40), a full 2^40 subset enumeration is too slow.
     * However, the problem asks for the MINIMUM REMOVALS, which means we want the MAXIMUM KEPT elements.
     * 
     * Let S be the set of all possible XOR sums of non-empty subsets of nums.
     * We want to find an XOR sum X in S such that X = target, and the subset used to achieve X is the largest possible.
     * 
     * Since N <= 40, Meet-in-the-Middle (MITM) is appropriate.
     * Split nums into two halves: nums1 (size N/2) and nums2 (size N - N/2).
     * 
     * 1. Generate all subset XOR sums for nums1, storing the maximum subset size for each sum.
     * 2. Generate all subset XOR sums for nums2, storing the maximum subset size for each sum.
     * 3. Combine the results: For every sum X1 from nums1 and sum X2 from nums2, check if X1 ^ X2 = target.
     *    If it is, we found a subset with XOR sum 'target' of size size(X1) + size(X2).
     * 4. The minimum removals = N - max_kept_size.
     */

    private static class SubsetInfo {
        // Maps XOR sum to the maximum size of the subset that achieves this XOR sum.
        // The key is the XOR sum. The value is the size of the subset.
        public java.util.Map<Long, Integer> map = new java.util.HashMap<>();
    }

    /**
     * Generates all possible subset XOR sums and tracks the maximum size for each sum.
     * @param nums The array segment.
     * @param start The starting index.
     * @param end The ending index (exclusive).
     * @return SubsetInfo containing the XOR sums and their max sizes.
     */
    private static SubsetInfo generateSubsets(long[] nums, int start, int end) {
        SubsetInfo info = new SubsetInfo();
        // Initialize with the empty set: XOR sum 0, size 0.
        info.map.put(0L, 0);

        for (int i = start; i < end; i++) {
            long currentNum = nums[i];
            // Create a temporary map to store new entries generated by including nums[i]
            java.util.Map<Long, Integer> newEntries = new java.util.HashMap<>();

            for (java.util.Map.Entry<Long, Integer> entry : info.map.entrySet()) {
                long existingXor = entry.getKey();
                int existingSize = entry.getValue();

                // New XOR sum = existing XOR sum ^ currentNum
                long newXor = existingXor ^ currentNum;
                int newSize = existingSize + 1;

                // Update the map: we only keep the maximum size for any given XOR sum
                newEntries.put(newXor, Math.max(
                    newEntries.getOrDefault(newXor, -1), 
                    newSize
                ));
            }

            // Merge new entries into the main map
            for (java.util.Map.Entry<Long, Integer> entry : newEntries.entrySet()) {
                long xor = entry.getKey();
                int size = entry.getValue();

                info.map.put(xor, Math.max(info.map.getOrDefault(xor, -1), size));
            }
        }
        return info;
    }

    public static long solve(long[] nums, long target) {
        int N = nums.length;
        if (N == 0) {
            return target == 0 ? 0 : -1;
        }

        // 1. Split the array (Meet-in-the-Middle)
        int mid = N / 2;

        // 2. Generate subsets for the first half
        SubsetInfo info1 = generateSubsets(nums, 0, mid);

        // 3. Generate subsets for the second half
        SubsetInfo info2 = generateSubsets(nums, mid, N);

        int maxKeptSize = -1;

        // 4. Combine results
        for (java.util.Map.Entry<Long, Integer> entry1 : info1.map.entrySet()) {
            long xor1 = entry1.getKey();
            int size1 = entry1.getValue();

            // We need xor1 ^ xor2 = target, so xor2 = target ^ xor1
            long requiredXor2 = target ^ xor1;

            if (info2.map.containsKey(requiredXor2)) {
                int size2 = info2.map.get(requiredXor2);

                // Total size = size1 + size2
                int currentKeptSize = size1 + size2;

                // Check if the combined subset is non-empty UNLESS target is 0 and both sizes are 0.
                // The problem implies we can choose an empty set resulting in XOR sum 0, size 0.
                // If target=0, the minimum removal is 0 (keeping the empty set).

                // The subsets generated always include the empty set (size 0, xor 0).

                // If size1 + size2 > 0, this is a valid non-empty subset.
                // If size1 + size2 == 0, it means xor1=0 and requiredXor2=0. This corresponds to keeping nothing.

                // If target != 0, we must have kept at least one element (size > 0).
                if (target != 0 && currentKeptSize == 0) {
                    continue;
                } 
                // If target == 0, keeping nothing (size 0) is a valid solution, but we aim for MAX size.

                maxKeptSize = Math.max(maxKeptSize, currentKeptSize);
            }
        }

        // Handle the case where the only way to reach target is keeping the empty set (target=0, maxKeptSize=0)
        if (target == 0 && maxKeptSize == -1) {
             // If target is 0, the empty set (size 0) always achieves it.
             maxKeptSize = 0;
        }


        if (maxKeptSize == -1) {
            return -1;
        }

        // Minimum removals = Total size - Maximum kept size
        return (long) N - maxKeptSize;
    }
}
