     * We can use the Meet-in-the-Middle technique.
     * Split nums into two halves, L and R, each of size up to 20.
     * 2^20 is about 1 million, which is manageable.
     *
     * Let S be the XOR sum of the remaining subset. We want S = target.
     * S = S_L XOR S_R, where S_L is the XOR sum of a subset of L, and S_R is
     * the XOR sum of a subset of R.
     * We need S_L XOR S_R = target, which means S_R = target XOR S_L.
     *
     * We iterate over all 2^|L| subsets of L, calculate their XOR sums (S_L),
     * and store the maximum size achieved for that S_L.
     * Then, we iterate over all 2^|R| subsets of R, calculate their XOR sums (S_R),
     * and check if target XOR S_R exists in our map/storage from L.
     *
     * Store: map<XOR_sum, max_subset_size> for the left half.
     */
    public static long solve(long[] nums, long target) {
        int n = nums.length;
        if (n == 0) {
            return target == 0 ? 0 : -1;
        }

        int n1 = n / 2;
        int n2 = n - n1;

        // Map to store: XOR_sum -> maximum size of subset achieving this XOR sum in the first half
        java.util.Map<Long, Integer> leftMap = new java.util.HashMap<>();

        // Generate all possible XOR sums and their maximum subset sizes for the left half (nums[0...n1-1])
        // Total 2^n1 possibilities
        for (int i = 0; i < (1 << n1); i++) {
            long currentXor = 0;
            int currentSize = 0;
            for (int j = 0; j < n1; j++) {
                if ((i & (1 << j)) != 0) {
                    currentXor ^= nums[j];
                    currentSize++;
                }
            }

            leftMap.put(currentXor, Math.max(leftMap.getOrDefault(currentXor, 0), currentSize));
        }

        // Initialize the maximum size found so far for the entire set (S_L XOR S_R = target)
        int maxTotalSize = -1;

        // Generate all possible XOR sums and their sizes for the right half (nums[n1...n-1])
        // Total 2^n2 possibilities
        for (int i = 0; i < (1 << n2); i++) {
            long currentXorR = 0;
            int currentSizeR = 0;
            for (int j = 0; j < n2; j++) {
                if ((i & (1 << j)) != 0) {
                    currentXorR ^= nums[n1 + j];
                    currentSizeR++;
                }
            }

            // We need S_L XOR S_R = target  =>  S_L = target XOR S_R
            long requiredXorL = target ^ currentXorR;

            if (leftMap.containsKey(requiredXorL)) {
                int sizeL = leftMap.get(requiredXorL);
                int totalSize = sizeL + currentSizeR;

                if (totalSize > maxTotalSize) {
                    maxTotalSize = totalSize;
                }
            }
        }

        if (maxTotalSize == -1) {
            return -1;
        } else {
            // Minimum removals = Total elements - Maximum remaining elements
            return (long)n - maxTotalSize;
        }
    }
}
